// friday13.cs — Find earliest Friday the 13th and count them in a 400-year cycle

// Earliest Friday the 13th starting from 0001-01-01 (proleptic Gregorian)
var date = new DateTime(1, 1, 13); // start checking the 13th of each month
DateTime? earliest = null;

while (date.Year == 1)
{
    if (date.DayOfWeek == DayOfWeek.Friday)
    {
        earliest = date;
        break;
    }
    date = date.AddMonths(1);
}

Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd}");
Console.WriteLine();

// Count Friday the 13ths in a full 400-year Gregorian cycle (years 1–400)
int count = 0;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateTime(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
            count++;
    }
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine();

// Bonus: distribution by month
var byMonth = new int[12];
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        if (new DateTime(year, month, 13).DayOfWeek == DayOfWeek.Friday)
            byMonth[month - 1]++;
    }
}

Console.WriteLine("Distribution by month:");
for (int m = 0; m < 12; m++)
    Console.WriteLine($"  {new DateTime(2000, m + 1, 1):MMMM,-12} {byMonth[m]}");

